# ══════════════════════════════════════════════════════════════════════

IS_WIN  = sys.platform == "win32"
IS_MAC  = sys.platform == "darwin"
IS_LIN  = sys.platform.startswith("linux")

CYAN    = "\033[96m" if not IS_WIN else ""
GREEN   = "\033[92m" if not IS_WIN else ""
YELLOW  = "\033[93m" if not IS_WIN else ""
RED     = "\033[91m" if not IS_WIN else ""
BOLD    = "\033[1m"  if not IS_WIN else ""
RESET   = "\033[0m"  if not IS_WIN else ""

def banner(msg):
    print(f"\n{BOLD}{CYAN}{'═'*60}{RESET}")
    print(f"{BOLD}{CYAN}  {msg}{RESET}")
    print(f"{BOLD}{CYAN}{'═'*60}{RESET}\n")

def step(msg):   print(f"  {GREEN}▶{RESET}  {msg}")
def warn(msg):   print(f"  {YELLOW}⚠{RESET}  {msg}")
def ok(msg):     print(f"  {GREEN}✓{RESET}  {msg}")
def err(msg):    print(f"  {RED}✕{RESET}  {msg}")

def run(cmd, **kw):
    return subprocess.run(cmd, check=True, **kw)

def run_quietly(cmd, **kw):
    return subprocess.run(cmd, check=True,
                          stdout=subprocess.DEVNULL,
                          stderr=subprocess.DEVNULL, **kw)

# ── Python version check ────────────────────────────────────────────
if sys.version_info < (3, 8):
    print(f"{RED}Python 3.8 or newer is required. You have {sys.version}{RESET}")
    sys.exit(1)

banner("WB Election Intel — Setup")
print(f"  Platform : {platform.system()} {platform.release()}")
print(f"  Python   : {sys.version.split()[0]}")

# ── Choose install folder ───────────────────────────────────────────
DEFAULT = Path.home() / "WB_Election_Intel"
print(f"\n  Default install folder: {DEFAULT}")
ans = input("  Press Enter to accept, or type a different path: ").strip()
DEST = Path(ans) if ans else DEFAULT
DEST.mkdir(parents=True, exist_ok=True)
ok(f"Install folder: {DEST}")

# ── Extract embedded files ──────────────────────────────────────────
banner("Extracting project files")
for name, b64z in EMBEDDED.items():
    out = DEST / name
    out.write_bytes(zlib.decompress(base64.b64decode(b64z.replace("\n",""))))
    ok(f"  {name}  ({out.stat().st_size//1024}KB)")

# ── Virtual environment ─────────────────────────────────────────────
banner("Setting up Python virtual environment")
VENV = DEST / "venv"
if VENV.exists():
    warn("venv already exists — skipping creation")
else:
    step("Creating venv...")
    run([sys.executable, "-m", "venv", str(VENV)])
    ok("venv created")

PY  = VENV / ("Scripts/python.exe" if IS_WIN else "bin/python3")
PIP = VENV / ("Scripts/pip.exe"    if IS_WIN else "bin/pip3")

# ── pip packages ────────────────────────────────────────────────────
banner("Installing Python packages")
PACKAGES = ["playwright", "python-pptx", "Pillow", "yt-dlp", "pypdf"]
step(f"Installing: {', '.join(PACKAGES)}")
run([str(PIP), "install", "--upgrade", "pip"], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
run([str(PIP), "install"] + PACKAGES)
ok("pip packages installed")

step("Installing Playwright Chromium browser...")
run([str(PY), "-m", "playwright", "install", "chromium"])
ok("Playwright Chromium installed")

# ── ffmpeg ──────────────────────────────────────────────────────────
banner("Installing ffmpeg")

def ffmpeg_ok():
    return shutil.which("ffmpeg") is not None or (DEST / "ffmpeg.exe").exists() or (DEST / "ffmpeg").exists()

if ffmpeg_ok():
    ok("ffmpeg already available")
elif IS_MAC:
    if shutil.which("brew"):
        step("Installing via Homebrew...")
        try:
            run(["brew", "install", "ffmpeg"])
            ok("ffmpeg installed via Homebrew")
        except subprocess.CalledProcessError:
            warn("Homebrew install failed — downloading static binary...")
            _install_ffmpeg_mac(DEST)
    else:
        warn("Homebrew not found — downloading static ffmpeg binary...")
        _install_ffmpeg_mac(DEST)
elif IS_WIN:
    _install_ffmpeg_win(DEST)
else:
    warn("Linux detected — trying apt/dnf...")
    try:
        run_quietly(["sudo", "apt-get", "install", "-y", "ffmpeg"])
        ok("ffmpeg installed via apt")
    except Exception:
        try:
            run_quietly(["sudo", "dnf", "install", "-y", "ffmpeg"])
            ok("ffmpeg installed via dnf")
        except Exception:
            warn("Could not auto-install ffmpeg. Please install manually: https://ffmpeg.org")

def _install_ffmpeg_mac(dest):
    import urllib.request, tarfile, tempfile
    URL = "https://evermeet.cx/ffmpeg/getrelease/ffmpeg/zip"
    step("Downloading ffmpeg static binary for macOS...")
    try:
        import zipfile, io
        with urllib.request.urlopen(URL, timeout=120) as r:
            data = r.read()
        with zipfile.ZipFile(io.BytesIO(data)) as zf:
            for member in zf.namelist():
                if "ffmpeg" in member.lower() and not member.endswith("/"):
                    target = dest / "ffmpeg"
                    target.write_bytes(zf.read(member))
                    target.chmod(0o755)
                    ok(f"ffmpeg extracted to {target}")
                    return
    except Exception as e:
        warn(f"Download failed: {e}")
        warn("Please install ffmpeg manually: brew install ffmpeg")

def _install_ffmpeg_win(dest):
    import urllib.request, zipfile, io
    URL = ("https://github.com/BtbN/FFmpeg-Builds/releases/download/latest/"
           "ffmpeg-master-latest-win64-gpl.zip")
    step("Downloading ffmpeg static binary for Windows (~80 MB)...")
    try:
        with urllib.request.urlopen(URL, timeout=300) as r:
            data = r.read()
        ok("Downloaded. Extracting ffmpeg.exe...")
        with zipfile.ZipFile(io.BytesIO(data)) as zf:
            for member in zf.namelist():
                if member.endswith("bin/ffmpeg.exe"):
                    target = dest / "ffmpeg.exe"
                    target.write_bytes(zf.read(member))
                    ok(f"ffmpeg.exe extracted to {target}")
                    return
    except Exception as e:
        warn(f"Download failed: {e}")
        warn("Please download ffmpeg manually from https://ffmpeg.org/download.html")
        warn("Extract ffmpeg.exe into: " + str(dest))

