if IS_WIN:
    bat = DEST / "START.bat"
    bat.write_text(textwrap.dedent(f"""\
        @echo off
        title WB Election Intel
        cd /d "%~dp0"
        set PATH=%~dp0;%PATH%
        echo Starting WB Election Intel proxy...
        venv\\Scripts\\python.exe proxy_local.py --backend ollama
        pause
    """))
    bat2 = DEST / "START_groq.bat"
    bat2.write_text(textwrap.dedent(f"""\
        @echo off
        title WB Election Intel — Groq
        cd /d "%~dp0"
        set PATH=%~dp0;%PATH%
        set /p GROQ_API_KEY=Enter Groq API key:
        venv\\Scripts\\python.exe proxy_local.py --backend groq
        pause
    """))
    ok("START.bat  (Ollama backend)")
    ok("START_groq.bat  (Groq cloud backend)")
else:
    sh = DEST / "start.sh"
    sh.write_text(textwrap.dedent(f"""\
        #!/bin/bash
        cd "$(dirname "$0")"
        export PATH="$(dirname "$0"):$PATH"
        source venv/bin/activate
        echo "Starting WB Election Intel proxy (Ollama)..."
        python3 proxy_local.py --backend ollama
    """))
    sh.chmod(0o755)
    sh_groq = DEST / "start_groq.sh"
    sh_groq.write_text(textwrap.dedent(f"""\
        #!/bin/bash
        cd "$(dirname "$0")"
        export PATH="$(dirname "$0"):$PATH"
        source venv/bin/activate
        read -p "Enter Groq API key: " GROQ_API_KEY
        export GROQ_API_KEY
        python3 proxy_local.py --backend groq
    """))
    sh_groq.chmod(0o755)
    cmd = DEST / "START.command"   # macOS double-click launcher
    cmd.write_text(textwrap.dedent(f"""\
        #!/bin/bash
        cd "$(dirname "$0")"
        export PATH="$(dirname "$0"):$PATH"
        source venv/bin/activate
        python3 proxy_local.py --backend ollama
    """))
    cmd.chmod(0o755)
    ok("start.sh  +  start_groq.sh  +  START.command (macOS double-click)")

